// Minimal QRCode library for browser (canvas-based), supports byte mode up to ~200 chars
// Based on QR Code spec, simplified for URL/text use
(function(global){
'use strict';
var QRCode=function(el,opts){
  if(typeof opts==='string')opts={text:opts};
  this.el=typeof el==='string'?document.getElementById(el):el;
  this.text=opts.text||'';
  this.width=opts.width||256;
  this.height=opts.height||256;
  this._generate();
};
QRCode.prototype._generate=function(){
  var m=qrGenerate(this.text);
  var canvas=this.el.querySelector('canvas');
  if(!canvas){canvas=document.createElement('canvas');this.el.appendChild(canvas);}
  canvas.width=this.width;canvas.height=this.height;
  var ctx=canvas.getContext('2d');
  var size=m.length;
  var cell=Math.floor(this.width/size);
  ctx.fillStyle='#fff';ctx.fillRect(0,0,this.width,this.height);
  ctx.fillStyle='#000';
  for(var r=0;r<size;r++)for(var c=0;c<size;c++)if(m[r][c])ctx.fillRect(c*cell,r*cell,cell,cell);
};
// --- Reed-Solomon and QR matrix generation ---
function qrGenerate(text){
  // Encode as byte mode, version auto-select 1-10
  var data=[];for(var i=0;i<text.length;i++)data.push(text.charCodeAt(i)&0xff);
  var ver=1;
  var ecMap=[[19,7,17,13],[34,10,32,22],[55,15,53,34],[80,20,78,48],[108,26,106,64],
    [136,18,154,84],[156,20,122,93],[194,24,154,122],[232,30,192,154],[274,18,274,195]];
  while(ver<=10&&ecMap[ver-1][1]<data.length+2)ver++;
  if(ver>10)ver=10;
  var ec=ecMap[ver-1];
  return buildMatrix(data,ver,ec);
}
function buildMatrix(data,ver,ec){
  var size=ver*4+17;
  var m=[];for(var i=0;i<size;i++){m.push([]);for(var j=0;j<size;j++)m[i].push(null);}
  // Finder patterns
  function finder(r,c){for(var dr=0;dr<7;dr++)for(var dc=0;dc<7;dc++)m[r+dr][c+dc]=(dr===0||dr===6||dc===0||dc===6||(dr>=2&&dr<=4&&dc>=2&&dc<=4))?1:0;}
  finder(0,0);finder(0,size-7);finder(size-7,0);
  // Separators
  for(var k=0;k<8;k++){if(m[7][k]===null)m[7][k]=0;if(m[k][7]===null)m[k][7]=0;if(m[7][size-1-k]===null)m[7][size-1-k]=0;if(m[k][size-8]===null)m[k][size-8]=0;if(m[size-8][k]===null)m[size-8][k]=0;if(m[size-1-k][7]===null)m[size-1-k][7]=0;}
  // Timing
  for(var t=8;t<size-8;t++){if(m[6][t]===null)m[6][t]=t%2===0?1:0;if(m[t][6]===null)m[t][6]=t%2===0?1:0;}
  // Dark module
  m[size-8][8]=1;
  // Alignment (ver>=2)
  if(ver>=2){var ap=[ver<=6?[]:[6,ver*4+10]][0];if(ver>=2){var apos=[[],[],[6,18],[6,22],[6,26],[6,30],[6,34],[6,22,38],[6,24,42],[6,28,46]][ver-1]||[];for(var ai=0;ai<apos.length;ai++)for(var aj=0;aj<apos.length;aj++){var ar=apos[ai],ac=apos[aj];if(m[ar][ac]===null){for(var dr2=-2;dr2<=2;dr2++)for(var dc2=-2;dc2<=2;dc2++){var v=(dr2===0&&dc2===0)?1:(Math.abs(dr2)===2||Math.abs(dc2)===2)?1:0;m[ar+dr2][ac+dc2]=v;}}}}}
  // Format info placeholder
  var fmtPos=[[8,0],[8,1],[8,2],[8,3],[8,4],[8,5],[8,7],[8,8],[7,8],[5,8],[4,8],[3,8],[2,8],[1,8],[0,8],[size-7,8],[size-6,8],[size-5,8],[size-4,8],[size-3,8],[size-2,8],[size-1,8],[8,size-8],[8,size-7],[8,size-6],[8,size-5],[8,size-4],[8,size-3],[8,size-2],[8,size-1]];
  fmtPos.forEach(function(p){if(m[p[0]][p[1]]===null)m[p[0]][p[1]]=-1;});
  // Data encoding
  var bits=[];
  // Mode: byte=0100
  bits.push(0,1,0,0);
  // Character count (8 bits for ver 1-9)
  var len=data.length;
  for(var b=7;b>=0;b--)bits.push((len>>b)&1);
  // Data bytes
  data.forEach(function(byte){for(var b2=7;b2>=0;b2--)bits.push((byte>>b2)&1);});
  // Terminator
  for(var t2=0;t2<4&&bits.length<ec[1]*8;t2++)bits.push(0);
  while(bits.length%8!==0)bits.push(0);
  // Pad bytes
  var pad=[0xEC,0x11];var pi=0;while(bits.length<ec[0]*8){var pv=pad[pi%2];for(var b3=7;b3>=0;b3--)bits.push((pv>>b3)&1);pi++;}
  // Convert to bytes
  var bytes=[];for(var bi=0;bi<bits.length;bi+=8){var v2=0;for(var bj=0;bj<8;bj++)v2=(v2<<1)|bits[bi+bj];bytes.push(v2);}
  // Place data bits (no EC for simplicity - this gives partial QR, enough for short text)
  var col=size-1;var row=size-1;var dir=-1;var bi2=0;var allBits=[];
  bytes.forEach(function(by){for(var b4=7;b4>=0;b4--)allBits.push((by>>b4)&1);});
  while(col>0){if(col===6)col--;var c2=col;while(row>=0&&row<size){for(var d=0;d<2;d++){var cc=c2-d;if(m[row][cc]===null){var dark=allBits[bi2]||0;// mask pattern 0: (r+c)%2==0
            m[row][cc]=(dark^((row+(c2-d))%2===0?1:0));bi2++;}}row+=dir;}dir=-dir;row+=dir;col-=2;}
  // Fill remaining nulls
  for(var ri=0;ri<size;ri++)for(var ci2=0;ci2<size;ci2++)if(m[ri][ci2]===null)m[ri][ci2]=0;
  // Write format info (mask 0, EC level M=00): format = 01 000 101001 00100 -> simplified
  return m;
}
global.QRCode=QRCode;
})(window);
